class Solution:
    def checkIfCanBreak(self, s1, s2):
        a, b = sorted(s1), sorted(s2)
        can_a = all(a[i] >= b[i] for i in range(len(a)))
        can_b = all(b[i] >= a[i] for i in range(len(a)))
        return can_a or can_b

