var checkIfCanBreak = function(s1, s2) {
    const a = s1.split('').sort();
    const b = s2.split('').sort();
    const n = a.length;
    let s1Breaks = true, s2Breaks = true;
    for (let i = 0; i < n; i++) {
        if (a[i] < b[i]) s1Breaks = false;
        if (b[i] < a[i]) s2Breaks = false;
    }
    return s1Breaks || s2Breaks;
};
